package ai.singlr.sail.gen;

import ai.singlr.sail.config.SailYaml;
import ai.singlr.sail.engine.AgentCli;
import java.util.List;
import java.util.Set;

/**
 * Generates cross-agent code review configuration files. When a secondary agent is configured as
 * reviewer, generates a bash script that invokes the reviewer to analyze code diffs for logic bugs,
 * edge cases, and quality issues.
 *
 * <p>Pure utility — no I/O, no shell execution. Callers push the generated files into the
 * container. Hooks configuration is handled by {@link PostTaskHooksGenerator}.
 */
public final class CodeReviewGenerator {

  private CodeReviewGenerator() {}

  /**
   * Generates the code review script for cross-agent bug detection. Returns an empty list if code
   * review is not enabled or no reviewer is available.
   *
   * @param config the project configuration
   * @param excludeAgents agents to skip during auto-resolution (e.g. the security auditor)
   */
  public static List<GeneratedFile> generateFiles(SailYaml config, Set<String> excludeAgents) {
    if (config.agent() == null
        || config.agent().codeReview() == null
        || !config.agent().codeReview().enabled()) {
      return List.of();
    }

    var review = config.agent().codeReview();
    var reviewerName =
        review.resolveAuditor(config.agent().type(), config.agent().install(), excludeAgents);
    if (reviewerName == null) {
      return List.of();
    }
    var reviewerBinary = AgentCli.fromYamlName(reviewerName).binaryName();
    var sshUser = config.sshUser();
    var scriptPath = "/home/" + sshUser + "/.sail/code-review.sh";

    var scriptContent = generateReviewScript(reviewerBinary);
    return List.of(new GeneratedFile(scriptPath, scriptContent, true));
  }

  /** Generates the bash review script that invokes the reviewer agent on the code diff. */
  static String generateReviewScript(String reviewerBinary) {
    return """
        #!/usr/bin/env bash
        set -euo pipefail

        # Cross-agent code review — invokes %s to review code changes for bugs.
        # Generated by `sail project create`. Do not edit.

        DIFF=$(git diff main..HEAD -- . ':!*.lock' ':!*.min.js' ':!*.min.css' 2>/dev/null || true)
        if [ -z "$DIFF" ]; then
          exit 0
        fi

        REVIEW_PROMPT="You are a code reviewer performing a thorough bug audit on a code diff. Analyze it for:
        1. Logic errors (wrong conditions, off-by-one, incorrect operators, wrong variable used)
        2. Edge cases (null/empty handling, boundary values, integer overflow, empty collections)
        3. Error handling gaps (uncaught exceptions, missing error paths, swallowed errors)
        4. Resource leaks (unclosed streams, connections, file handles, thread pools)
        5. Concurrency issues (race conditions, thread safety, shared mutable state, deadlocks)
        6. Performance pitfalls (N+1 queries, unbounded growth, unnecessary allocations, quadratic loops)
        7. API contract violations (wrong return types, missing validations, broken invariants)
        8. Data integrity issues (lost updates, partial writes, inconsistent state transitions)

        For each issue found, report:
        - File and line number
        - Severity (critical/high/medium/low)
        - Description of the bug or issue
        - Recommended fix

        If the code is clean and no issues are found, respond with exactly: PASS

        --- BEGIN DIFF ---
        ${DIFF}
        --- END DIFF ---"

        RESULT=$(%s --print "$REVIEW_PROMPT" 2>/dev/null || echo "REVIEW_ERROR")

        if echo "$RESULT" | grep -q "^PASS"; then
          exit 0
        else
          echo "$RESULT" > ~/code-review.md
          echo "Code review found issues. See ~/code-review.md" >&2
          exit 2
        fi
        """
        .formatted(reviewerBinary, reviewerBinary);
  }
}
